        {"id": 32, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "The research methodology must be precisely described."}, "answer": "Metodologija istraživanja mora biti precizno opisana.", "hint": "metodologija, opisana"},
        {"id": 33, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "Having finished the experiment, the team analysed the results."}, "answer": "Završivši eksperiment, tim je analizirao rezultate.", "hint": "Glagolski prilog prošli: završivši"},
        {"id": 34, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "We propose that additional testing be conducted."}, "answer": "Predlažemo da se provede dodatno testiranje.", "hint": "da + prezent konjunktiva"},
        {"id": 35, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "Empirical evidence supports this theory."}, "answer": "Empirijski dokazi podupiru ovu teoriju.", "hint": "empirijski, podupirati"},
        {"id": 36, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "The doctoral candidate defends their dissertation tomorrow."}, "answer": "Doktorand brani disertaciju sutra.", "hint": "doktorand, braniti disertaciju"},
        {"id": 37, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "We must control all independent variables."}, "answer": "Moramo kontrolisati sve nezavisne varijable.", "hint": "varijable, nezavisne"},
        {"id": 38, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "The discovery changed the scientific paradigm."}, "answer": "Otkriće je promijenilo naučnu paradigmu.", "hint": "paradigma, promijeniti"},
        {"id": 39, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "He said that the hypothesis was correct."}, "answer": "Rekao je da je hipoteza tačna.", "hint": "Neupravni govor: da + prezent"},
        {"id": 40, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "The paper underwent double-blind peer review."}, "answer": "Rad je prošao dvostruku anonimnu recenziju.", "hint": "recenzija, proći recenziju"},
        {"id": 41, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Istraživanje je trajalo pet godina."}, "answer": "The research lasted five years.", "hint": "istraživanje = research, trajati = to last"},
        {"id": 42, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Istražujući fenomen, naučnici su otkrili nešto neočekivano."}, "answer": "While investigating the phenomenon, the scientists discovered something unexpected.", "hint": "istražujući = while investigating"},
        {"id": 43, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Nalazi studije su objavljeni u prestižnom časopisu."}, "answer": "The study's findings were published in a prestigious journal.", "hint": "nalazi = findings, objavljeni = published"},
        {"id": 44, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Dobili smo grant za trogodišnje istraživanje."}, "answer": "We received a grant for a three-year study.", "hint": "grant, trogodišnji = three-year"},
        {"id": 45, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Rekli su da će provesti eksperiment."}, "answer": "They said they would conduct the experiment.", "hint": "Neupravni govor u budućnosti"},
        {"id": 46, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Laboratorija je opremljena najmodernijim uređajima."}, "answer": "The laboratory is equipped with state-of-the-art instruments.", "hint": "opremljena = equipped"},
        {"id": 47, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Replikacija rezultata je osnova pouzdanosti u nauci."}, "answer": "Replication of results is the foundation of reliability in science.", "hint": "replikacija = replication, pouzdanost = reliability"},
        {"id": 48, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Cilj istraživanja je da se utvrdi uzrok bolesti."}, "answer": "The aim of the research is to determine the cause of the disease.", "hint": "utvrdi = determine, bolest = disease"},
        {"id": 49, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Njegova publikacija je citirana stotine puta."}, "answer": "His publication has been cited hundreds of times.", "hint": "citirana = cited, stotine puta = hundreds of times"},
        {"id": 50, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Obavivši recenziju, urednici su odbacili rad."}, "answer": "Having completed the review, the editors rejected the paper.", "hint": "obavivši = having completed"},
        {"id": 51, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Šta je 'glagolski prilog prošli'?", "options": ["A present participle used simultaneously with the main verb", "A past participle describing an action completed before the main verb", "A passive verb form", "An infinitive construction"]}, "answer": "A past participle describing an action completed before the main verb", "hint": "Završivši, pročitavši, obavivši..."},
        {"id": 52, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Koji je ispravni neupravni govor od: \"Provest ćemo eksperiment.\"?", "options": ["Rekli su provesti eksperiment.", "Rekli su da će provesti eksperiment.", "Rekli su da provode eksperiment.", "Rekli su ako provedu eksperiment."]}, "answer": "Rekli su da će provesti eksperiment.", "hint": "Futur u neupravnom govoru: da + futur"},
        {"id": 53, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Šta znači 'empirijski dokazi'?", "options": ["theoretical evidence", "empirical evidence", "historical evidence", "circumstantial evidence"]}, "answer": "empirical evidence", "hint": "empirijski = empirical"},
        {"id": 54, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Koji oblik je glagolski prilog sadašnji od 'istraživati'?", "options": ["istražio", "istraživan", "istražujući", "istraživavši"]}, "answer": "istražujući", "hint": "3. lice mn. prezenta: istražuju → istražujući"},
        {"id": 55, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Šta je 'recenzija' u naučnom kontekstu?", "options": ["a research grant", "peer review", "a laboratory", "a hypothesis"]}, "answer": "peer review", "hint": "Naučnici ocjenjuju rad kolege"},
        {"id": 56, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Koja rečenica koristi subjunktiv ispravno?", "options": ["Cilj je utvrdi uzrok.", "Cilj je da se utvrdi uzrok.", "Cilj je utvrđuje uzrok.", "Cilj je utvrđen uzrok."]}, "answer": "Cilj je da se utvrdi uzrok.", "hint": "da + prezent = subjunktivna konstrukcija"},
        {"id": 57, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Šta znači 'paradigma' u nauci?", "options": ["an experiment", "a variable", "a dominant framework or model", "a publication"]}, "answer": "a dominant framework or model", "hint": "Kuhn: naučna revolucija = promjena paradigme"},
        {"id": 58, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Koja je razlika između 'istražujući' i 'istražavši'?", "options": ["There is no difference", "'Istražujući' is simultaneous; 'istražavši' shows prior completion", "'Istražujući' is passive; 'istražavši' is active", "'Istražujući' is plural; 'istražavši' is singular"]}, "answer": "'Istražujući' is simultaneous; 'istražavši' shows prior completion", "hint": "Prilog sadašnji vs. prilog prošli"},
        {"id": 59, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Šta je 'varijabla' u istraživanju?", "options": ["a hypothesis", "a factor that can change and be measured", "a peer reviewer", "a research grant"]}, "answer": "a factor that can change and be measured", "hint": "varijabla = variable – nešto što se može mijenjati"},
        {"id": 60, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Kako prevedemo: 'The findings were replicated'?", "options": ["Nalazi su replicirani.", "Nalazi repliciraju.", "Nalazi će replicirati.", "Nalazi su replicirali."]}, "answer": "Nalazi su replicirani.", "hint": "Pasivna konstrukcija: biti + glagolski pridjev trpni"},
        {"id": 61, "type": "word_form", "instruction": "Upišite odgovarajući oblik", "content": {"sentence": "Rekao je da _____ provesti eksperiment. (htjeti)", "base_word": "htjeti"}, "answer": "će", "hint": "Futur u neupravnom govoru, 3. lice množine"},
        {"id": 62, "type": "word_form", "instruction": "Upišite odgovarajući oblik", "content": {"sentence": "Metodologija je precizno _____. (opisati)", "base_word": "opisati"}, "answer": "opisana", "hint": "Pasivni pridjev trpni, ženski rod"},
        {"id": 63, "type": "word_form", "instruction": "Upišite odgovarajući oblik", "content": {"sentence": "_____ podatke, naučnik je primijetio grešku. (analizirati)", "base_word": "analizirati"}, "answer": "Analizirajući", "hint": "Glagolski prilog sadašnji"},
        {"id": 64, "type": "word_form", "instruction": "Upišite odgovarajući oblik", "content": {"sentence": "_____ disertaciju, doktorand je aplicirao za posao. (odbraniti)", "base_word": "odbraniti"}, "answer": "Odbranivši", "hint": "Glagolski prilog prošli"},
