        {"id": 70, "type": "word_form", "instruction": "Upišite odgovarajući oblik", "content": {"sentence": "Laboratorija je _____ najmodernijim uređajima. (opremiti)", "base_word": "opremiti"}, "answer": "opremljena", "hint": "Pasivni pridjev trpni, ženski rod"},
