        {"id": 77, "type": "dialogue_complete", "instruction": "Dopunite dijalog", "content": {"context": "Pitanje o objavljivanju", "dialogue": "Urednik: Gdje ste objavili vaše nalaze?\nIstraživač: _____"}, "answer": "Objavili smo ih u prestižnom naučnom časopisu.", "hint": "časopis = journal"},
        {"id": 78, "type": "dialogue_complete", "instruction": "Dopunite dijalog", "content": {"context": "Razgovor o paradigmi", "dialogue": "Student: Zašto je ovo otkriće važno?\nProfesor: _____"}, "answer": "Zato što mijenja naučnu paradigmu u ovoj oblasti.", "hint": "Objasnite važnost promjene paradigme"},
        {"id": 79, "type": "dialogue_complete", "instruction": "Dopunite dijalog", "content": {"context": "Pitanje o varijablama", "dialogue": "Recenzent: Jeste li kontrolisali sve varijable?\nIstraživač: _____"}, "answer": "Jesmo. Kontrolisali smo sve nezavisne varijable.", "hint": "nezavisne varijable = independent variables"},
