        {"id": 3, "question": "Šta znači 'recenzija' u naučnom kontekstu?", "options": ["dissertation", "peer review", "laboratory", "methodology"], "correct_answer": 1, "explanation": "'Recenzija' je peer review – ocjenjivanje rada od strane stručnjaka.", "question_type": "vocabulary"},
        {"id": 4, "question": "Koji oblik je ispravan: 'Završivši eksperiment, tim _____ rezultate.'", "options": ["je analizirao", "analizira", "analizirati", "analizujući"], "correct_answer": 0, "explanation": "Nakon glagolskog priloga prošlog, slijedi perfekat: 'je analizirao'.", "question_type": "grammar"},
        {"id": 5, "question": "Šta znači 'empirijski dokazi'?", "options": ["theoretical evidence", "circumstantial evidence", "empirical evidence", "anecdotal evidence"], "correct_answer": 2, "explanation": "'Empirijski' znači empirical – zasnovan na iskustvu i mjerenjima.", "question_type": "vocabulary"},
        {"id": 6, "question": "Koji je ispravni neupravni govor od: \"Hipoteza je tačna.\"?", "options": ["Rekao je hipoteza je tačna.", "Rekao je da je hipoteza tačna.", "Rekao je ako je hipoteza tačna.", "Rekao je hipotezu tačna."], "correct_answer": 1, "explanation": "Neupravni govor izjavnih rečenica: 'da + prezent/perfekat'.", "question_type": "grammar"},
        {"id": 7, "question": "Šta je 'metodologija istraživanja'?", "options": ["the final results", "the systematic approach and methods used in research", "a research grant", "a peer-reviewed journal"], "correct_answer": 1, "explanation": "'Metodologija' opisuje sistematski pristup i metode korištene u istraživanju.", "question_type": "vocabulary"},
        {"id": 8, "question": "Koja rečenica koristi glagolski prilog sadašnji ispravno?", "options": ["Istražio podatke, naučnik je objavio rad.", "Istražujući podatke, naučnik je objavio rad.", "Da istraži podatke, naučnik je objavio rad.", "Istražen podacima, naučnik je objavio rad."], "correct_answer": 1, "explanation": "'Istražujući' je glagolski prilog sadašnji – istovremena radnja.", "question_type": "grammar"},
        {"id": 9, "question": "Šta znači 'replikacija rezultata'?", "options": ["publishing results", "replication of results", "falsification of results", "summary of results"], "correct_answer": 1, "explanation": "'Replikacija' je replication – ponavljanje eksperimenta radi provjere rezultata.", "question_type": "vocabulary"},
        {"id": 10, "question": "Koji je ispravni subjunktivni oblik: 'Potrebno je da rezultati _____ replicirani.'?", "options": ["su", "budu", "bili", "jesu"], "correct_answer": 1, "explanation": "Subjunktiv: da + prezent – 'da budu replicirani'.", "question_type": "grammar"},
        {"id": 11, "question": "Šta je 'doktorand'?", "options": ["a professor", "a doctoral candidate / PhD student", "a peer reviewer", "a laboratory assistant"], "correct_answer": 1, "explanation": "'Doktorand' je osoba koja radi na doktoratu (PhD student).", "question_type": "vocabulary"},
        {"id": 12, "question": "Koji glagolski prilog prošli je od 'pročitati'?", "options": ["pročitajući", "pročitavši", "pročitan", "pročitanje"], "correct_answer": 1, "explanation": "Glagolski prilog prošli od 'pročitati' je 'pročitavši' (having read).", "question_type": "grammar"},
        {"id": 13, "question": "Šta znači 'paradigma' u nauci?", "options": ["an experiment", "a research variable", "a dominant model or framework", "a laboratory instrument"], "correct_answer": 2, "explanation": "'Paradigma' je dominant model or framework – temeljni okvir naučnog mišljenja.", "question_type": "vocabulary"},
