        {"id": 17, "question": "Šta je 'disertacija'?", "options": ["a research grant", "a dissertation / thesis", "a peer review", "a scientific journal"], "correct_answer": 1, "explanation": "'Disertacija' je dissertation ili thesis – opsežan naučni rad.", "question_type": "vocabulary"},
        {"id": 18, "question": "Koji je ispravni neupravni govor upitne rečenice: \"Jeste li dobili grant?\"", "options": ["Pitao je da su dobili grant.", "Pitao je jesu li dobili grant.", "Pitao je ako dobili grant.", "Pitao je što su dobili grant."], "correct_answer": 1, "explanation": "Upitni neupravni govor da/ne pitanja: 'jesu li' (whether they had).", "question_type": "grammar"},
